SELECT count(*) FROM products p
LEFT JOIN categories c ON p.category_id = c.id

    p."stateId" = 'PUBLISHED'
    AND p.name LIKE #{name}
    AND p.brand = #{brand}
    AND p.category_id = #{categoryId}

SELECT p.id, p.name, p.description, p.short_description as "shortDescription", p.brand, p.category_id as "categoryId", c.name as "categoryName", p.slug, p."stateId" as "stateId" FROM products p LEFT JOIN categories c ON p.category_id = c.id
p."stateId" = 'PUBLISHED' AND p.name LIKE #{name} AND p.brand = #{brand} AND p.category_id = #{categoryId}
${orderby} ${pagination}

SELECT count(*) FROM products p
LEFT JOIN categories c ON p.category_id = c.id

    p.name LIKE #{name}
    AND p.brand = #{brand}
    AND p.category_id = #{categoryId}
    AND p.slug = #{slug}
    AND p."stateId" = #{stateId}

SELECT
    p.id, p.name, p.description,
    p.short_description as "shortDescription",
    p.brand,
    p.category_id as "categoryId",
    c.name as "categoryName",
    p.slug,
    p."stateId" as "stateId"
FROM products p
LEFT JOIN categories c ON p.category_id = c.id

    p.name LIKE #{name}
    AND p.brand = #{brand}
    AND p.category_id = #{categoryId}
    AND p.slug = #{slug}
    AND p."stateId" = #{stateId}

${orderby} ${pagination}
